// Recupere les donnees du devis envoyees par le site et prepare
// le fichier PDF (decode depuis le base64) pour Zoho Sign.
const body = $json.body || $json;
const fileName = `devis-${body.devis_numero || 'sans-numero'}.pdf`;

const createData = JSON.stringify({
  requests: {
    request_name: `Devis ${body.devis_numero || ''}`.trim(),
    actions: [
      {
        recipient_name: `${body.prenom || ''} ${body.nom || ''}`.trim(),
        recipient_email: body.email,
        action_type: 'SIGN',
        signing_order: 0,
        verify_recipient: false,
      },
    ],
    expiration_days: 30,
    is_sequential: false,
    email_reminders: true,
  },
});

return [{
  json: { body, createData },
  binary: {
    document: {
      data: body.pdf_base64,
      mimeType: 'application/pdf',
      fileName,
    },
  },
}];

// Lit la reponse de creation Zoho Sign et construit la requete de
// soumission, avec un champ de signature place sur la zone prevue
// du PDF (bas de page).
const resp = $json;
const reqObj = resp.requests || {};
const requestId = reqObj.request_id;
const documentId =
  (reqObj.document_ids && reqObj.document_ids[0] && reqObj.document_ids[0].document_id) || '';
const action = (reqObj.actions && reqObj.actions[0]) || {};

const submitData = JSON.stringify({
  requests: {
    actions: [
      {
        action_id: action.action_id,
        action_type: 'SIGN',
        recipient_name: action.recipient_name,
        recipient_email: action.recipient_email,
        signing_order: 0,
        verify_recipient: false,
        fields: [
          {
            field_name: 'Signature',
            field_type_name: 'Signature',
            field_category: 'signature',
            document_id: documentId,
            page_no: 0,
            is_mandatory: true,
            x_coord: 210,
            y_coord: 690,
            abs_width: 160,
            abs_height: 40,
          },
        ],
      },
    ],
  },
});

return [{ json: { requestId, submitData } }];
